/**
 * Scan wiki/ directory for references to fact IDs. Returns a map of
 * factId → list of wiki files that reference it.
 */
export function checkWikiReferences(factIds: string[]): Record<string, string[]> {
  if (factIds.length === 0) return {};
  const wikiDir = path.join(resolveMemoryDir(), "wiki");
  if (!existsSync(wikiDir)) return {};
  const refs: Record<string, string[]> = {};
  const scan = (dir: string) => {
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      const full = path.join(dir, entry.name);
      if (entry.isDirectory()) { scan(full); continue; }
      if (!entry.name.endsWith(".md")) continue;
      const content = readFileSync(full, "utf8");
      for (const id of factIds) {
        if (content.includes(`f_${id}`)) {
          (refs[id] ??= []).push(path.relative(wikiDir, full).replace(/\\/g, "/"));
        }
      }
    }
  };
  scan(wikiDir);
  return refs;
}

/**
 * Delete every master-log line that matches `query` (case-insensitive
 * substring on the stripped fact text), then rebuild all shards. Returns
 * the deleted lines + fresh per-topic counts.
 *
 * If `expectedToken` is provided it must equal computeForgetToken(current
 * matches) — otherwise the call throws and nothing is written. This lets
 * the MCP tool implement a two-phase confirm without server-side state.
 */
export function forgetCommit(opts: {
  userId: number | string;
  query: string;
  expectedToken?: string;
}): {
  deleted: ForgetMatch[];
  wikiProtected: { match: ForgetMatch; referencedBy: string[] }[];
  remaining: number;
  shardSummary: { total: number; perTopic: Record<string, number> };
} {
  const { userId, query, expectedToken } = opts;
  const { matches, token } = forgetMatch(userId, query);
  if (matches.length === 0) {
    throw new Error(`no facts match query: ${JSON.stringify(query)}`);
  }
  if (expectedToken && expectedToken.trim() !== token) {
    throw new Error(
      `confirm token mismatch (got=${expectedToken}, expected=${token}); ` +
        `the master log changed since you previewed — call forget without ` +
        `confirm to re-preview.`
    );
  }

  // Check wiki references — protect facts that are cited by wiki pages.
  const factIds = matches.map(m => extractFactId(m.line)).filter((id): id is string => !!id);
  const wikiRefs = checkWikiReferences(factIds);
  const wikiProtected: { match: ForgetMatch; referencedBy: string[] }[] = [];
  const deletable: ForgetMatch[] = [];
  for (const m of matches) {
    const id = extractFactId(m.line);
    if (id && wikiRefs[id]?.length) {
      wikiProtected.push({ match: m, referencedBy: wikiRefs[id] });
    } else {
      deletable.push(m);
    }
  }

  // Rewrite master log with deletable indices stripped (wiki-protected kept).
  const master = masterFactsFile(userId);
  const allLines = readMasterLines(userId);
  const dropIdx = new Set(deletable.map((m) => m.index));
  const kept = allLines.filter((_, i) => !dropIdx.has(i));
  writeFileSync(master, kept.join("\n") + (kept.length ? "\n" : ""), "utf8");

  // Rebuild shards from the new master log so topic counts stay accurate
  // even if the same fact lived in multiple shards after a topics.json
  // edit (shouldn't happen with first-match-wins classify, but cheap
  // insurance).
  const shardSummary = rebuildShards(userId);

  appendForgetLog({ userId, query, deleted: deletable, token });

  return {
    deleted: deletable,
    wikiProtected,
    remaining: kept.length,
    shardSummary: { total: shardSummary.total, perTopic: shardSummary.perTopic },
  };
}

/** Append an audit entry to forget-log.md. Swallows I/O errors. */
export function appendForgetLog(opts: {
  userId: number | string;
  query: string;
  deleted: ForgetMatch[];
  token: string;
}): void {
  try {
    const dir = resolveMemoryDir();
    mkdirSync(dir, { recursive: true });
    const file = forgetLogFile();
    const ts = new Date().toISOString();
    const head =
      `- [${ts}] user=${opts.userId} query=${JSON.stringify(opts.query)} ` +
      `deleted=${opts.deleted.length} token=${opts.token}\n`;
    const body = opts.deleted.map((m) => `    ${m.line}`).join("\n");
    const existing = existsSync(file) ? readFileSync(file, "utf8") : "";
    const prefix = existing.length > 0 && !existing.endsWith("\n") ? "\n" : "";
    appendFileSync(file, prefix + head + body + "\n", "utf8");

function readMasterLines(userId: number | string): string[] {
  const file = masterFactsFile(userId);
  try {
    const raw = readFileSync(file, "utf8");
    return raw
      .split(/\r?\n/)
      .map((l) => l.replace(/\s+$/, ""))
      .filter((l) => l.trim().length > 0);
  } catch {
    return [];
  }
}

