  const perTopic: Record<string, number> = {};
  // Group lines by topic then write each file in one shot — faster and
  // avoids many appendFileSync calls when the master log is large.
  const grouped = new Map<string, string[]>();
  for (const line of lines) {
    const text = line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim();
    const topic = classifyFact(text) || "misc";
    if (!grouped.has(topic)) grouped.set(topic, []);
    grouped.get(topic)!.push(line);
    perTopic[topic] = (perTopic[topic] ?? 0) + 1;
  }
  for (const [topic, bucket] of grouped) {
    const file = path.join(dir, topicToFilename(topic));
    writeFileSync(file, bucket.join("\n") + "\n", "utf8");
  }
  return { total: lines.length, perTopic, shardDir: dir };
}

/**
 * Helper used by both writers to format a fact line consistently. Returns
 * "- [ISO] text\n" ready to append to either the master log or a shard.
 */
/** Generate a 6-char hex hash for fact traceability. */
export function generateFactId(text: string): string {
  return createHash("sha256").update(text.trim()).digest("hex").slice(0, 6);
}

export function formatFactLine(text: string, ts?: string): string {
  const t = (ts ?? new Date().toISOString()).trim();
  const id = generateFactId(text);
  return `- [f_${id}] [${t}] ${text.trim()}\n`;
}

/** Strip "- [f_xxxxxx] [timestamp] " or "- [timestamp] " prefix. */
export function stripFactPrefix(line: string): string {
  return line.replace(/^\s*-\s*(?:\[f_[0-9a-f]{6}\]\s*)?\[[^\]]+\]\s*/, "").trim();
}

/** Extract fact ID from a formatted line, or null if none. */
export function extractFactId(line: string): string | null {
  const m = line.match(/\[f_([0-9a-f]{6})\]/);
  return m ? m[1] : null;
}

