export interface ShardInfo {
  topic: string; // topic name derived from filename (sans .md)
  file: string; // absolute path
  count: number; // non-empty lines
}

/**
 * List every shard file currently on disk for this user with its line
 * count. Returns [] if the shard dir doesn't exist. Files are sorted by
 * count descending so callers can use the order directly in the preamble
 * index.
 */
export function listTopicShards(userId: number | string): ShardInfo[] {
  const dir = userShardDir(userId);
  if (!existsSync(dir)) return [];
  let entries: string[];
