  throw new Error(
    `[forgetCommit] refuse to delete ${deletable.length}/${allLines.length} facts ` +
      `(exceeds 50% threshold). Use smaller, more specific queries.`
  );
}

// Safety: backup master log before rewrite.
try {
  copyFileSync(master, `${master}.bak.${Date.now()}`);
} catch {
  /* best-effort — don't block the operation if backup fails */
}

writeFileSync(master, kept.join("\n") + (kept.length ? "\n" : ""), "utf8");

